INSERT INTO TBL_WEBFOLDER_CONFIG (
	TENANT_ID, COMPANY_ID, UPLOAD_LIMIT, COMPANY_TOTAL_LIMIT, DEPARTMENT_TOTAL_LIMIT, USER_TOTAL_LIMIT
)
VALUES (
	#tenantId#, '*', #uploadLimit#, #companyLimit#, #departmentLimit#, #userLimit#
)


INSERT INTO TBL_WEBFOLDER_CONFIG (
	TENANT_ID, COMPANY_ID, UPLOAD_LIMIT, COMPANY_TOTAL_LIMIT, DEPARTMENT_TOTAL_LIMIT, USER_TOTAL_LIMIT
)
VALUES (
	#tenantId#, #companyId#, #uploadLimit#, #companyLimit#, #departmentLimit#, #userLimit#
)


INSERT INTO TBL_WEBFOLDER_USER (
	CN, TYPE, TOTAL_CAPACITY, COMPANY_ID, TENANT_ID
)
VALUES (
	#cn#, #type#, #value#, #companyId#, #tenantId#
)


INSERT INTO TBL_WEBFOLDER_CONFIG (
	TENANT_ID, COMPANY_ID, COMPANY_TOTAL_LIMIT
) VALUES (
	#tenantId#, #cn#, #value#
)


INSERT INTO TBL_WEBFOLDER_USER (
	CN,          TOTAL_CAPACITY,       COMPANY_ID,       TENANT_ID
)
VALUES (
	#userId#,    #totalCapacity#,      #companyId#,      #tenantId#
)

sqlMap.select:
SELECT * FROM ( SELECT k.*, ROWNUM AS RNUM FROM ( SELECT l.LOG_ID AS LOG_ID, CASE WHEN t.TYPE_ICON IS NOT NULL THEN t.TYPE_ICON ELSE (SELECT TYPE_ICON FROM TBL_WEBFOLDER_FILETYPE WHERE FILE_EXT = 'unknown' AND TENANT_ID = #tenantId#) END AS FILE_TYPE, l.FILE_NAME AS FILE_NAME, l.FILE_SIZE AS FILE_SIZE, l.FILE_EXT AS FILE_EXT, l.LOG_TYPE AS LOG_TYPE, l.CREATE_ID AS CREATE_ID, l.CREATE_NAME1 AS CREATE_NAME1, l.CREATE_NAME2 AS CREATE_NAME2, (l.CREATE_DATE + #offset#/(24*60)) AS CREATE_DATE, l.COMPANY_ID AS COMPANY_ID, l.TENANT_ID AS TENANT_ID FROM TBL_WEBFOLDER_LOG l LEFT JOIN TBL_WEBFOLDER_FILETYPE t ON LOWER(l.FILE_EXT) = LOWER(t.FILE_EXT) AND l.TENANT_ID = t.TENANT_ID
ORDER BY $realColmn$ $order$, l.CREATE_DATE DESC, TO_NUMBER(l.LOG_ID) DESC
ORDER BY l.CREATE_DATE DESC, TO_NUMBER(l.LOG_ID) DESC
) k WHERE ROWNUM <= #startPoint# + #pageSize# ) WHERE RNUM >= #startPoint# + 1
) k )
